def regular_pricing(base_price, quantity):
    return base_price * quantity

def premium_pricing(base_price, quantity):
    discount = 0.1 if quantity >= 5 else 0
    return base_price * quantity * (1 - discount)

def student_pricing(base_price, quantity):
    return base_price * quantity * 0.8

